export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export type CSVRow = Record<string, any>;

export interface CSVResult {
  rows: CSVRow[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: CSVRow) => boolean): CSVRow[];
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, CSVRow[]>;
}

const NUMBER_REGEX = /^-?\d+(\.\d+)?$/;

function coerceValue(value: string): any {
  const trimmed = value.trim();
  if (trimmed === "" || /^null$/i.test(trimmed)) {
    return null;
  }
  if (/^(true|false)$/i.test(trimmed)) {
    return trimmed.toLowerCase() === "true";
  }
  if (NUMBER_REGEX.test(trimmed)) {
    return Number(trimmed);
  }
  return value;
}

function detectLineSeparator(input: string): string {
  if (input.includes("\r\n")) {
    return "\r\n";
  }
  return "\n";
}

export function parseCSV(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ",";
  const quote = options.quote ?? '"';
  const lineSeparator = options.lineSeparator ?? detectLineSeparator(input);

  const rowsRaw: string[][] = [];
  const errors: CSVError[] = [];

  let row: string[] = [];
  let current = "";
  let inQuotes = false;
  let rowNumber = 1;
  let i = 0;

  const pushField = () => {
    row.push(current);
    current = "";
  };

  while (i < input.length) {
    const char = input[i];

    if (inQuotes) {
      if (char === quote) {
        if (input[i + 1] === quote) {
          current += quote;
          i += 2;
          continue;
        }
        inQuotes = false;
        i += 1;
        continue;
      }
      current += char;
      i += 1;
      continue;
    }

    if (char === quote && current.length === 0) {
      inQuotes = true;
      i += 1;
      continue;
    }

    if (input.startsWith(lineSeparator, i)) {
      pushField();
      rowsRaw.push(row);
      row = [];
      current = "";
      i += lineSeparator.length;
      rowNumber += 1;
      continue;
    }

    if (char === delimiter) {
      pushField();
      i += 1;
      continue;
    }

    current += char;
    i += 1;
  }

  if (inQuotes) {
    errors.push({ row: rowNumber, message: "Unmatched quote" });
  }

  if (current.length > 0 || row.length > 0) {
    pushField();
    rowsRaw.push(row);
  }

  if (rowsRaw.length === 0) {
    return buildResult([], [], errors);
  }

  const headers = rowsRaw[0].map((header) => header.trim());
  const rows: CSVRow[] = [];

  for (let idx = 1; idx < rowsRaw.length; idx += 1) {
    const rawRow = rowsRaw[idx];
    if (rawRow.length !== headers.length) {
      errors.push({
        row: idx + 1,
        message: `Expected ${headers.length} fields but got ${rawRow.length}`,
      });
    }

    const record: CSVRow = {};
    for (let col = 0; col < headers.length; col += 1) {
      const header = headers[col];
      const value = rawRow[col] ?? "";
      record[header] = coerceValue(value);
    }
    rows.push(record);
  }

  return buildResult(rows, headers, errors);
}

function buildResult(rows: CSVRow[], headers: string[], errors: CSVError[]): CSVResult {
  return {
    rows,
    headers,
    errors,
    filter(predicate: (row: CSVRow) => boolean) {
      return rows.filter(predicate);
    },
    sum(column: string) {
      let total = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number" && Number.isFinite(value)) {
          total += value;
        }
      }
      return total;
    },
    average(column: string) {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number" && Number.isFinite(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count() {
      return rows.length;
    },
    groupBy(column: string) {
      const map = new Map<any, CSVRow[]>();
      for (const row of rows) {
        const key = row[column];
        if (!map.has(key)) {
          map.set(key, []);
        }
        map.get(key)!.push(row);
      }
      return map;
    },
  };
}

import { parseCSV } from "./csv-parser";

function assert(condition: boolean, message: string) {
  if (!condition) {
    throw new Error(message);
  }
}

function assertEqual(actual: any, expected: any, message: string) {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(`${message}. Expected ${expectedJson} but got ${actualJson}`);
  }
}

(function testBasicParsing() {
  const input = "name,age\nAlice,30\nBob,25";
  const result = parseCSV(input);
  assertEqual(result.headers, ["name", "age"], "Headers should parse");
  assert(result.rows.length === 2, "Should parse two rows");
  assertEqual(result.rows[0], { name: "Alice", age: 30 }, "First row parsed");
  assertEqual(result.rows[1], { name: "Bob", age: 25 }, "Second row parsed");
})();

(function testQuotedFieldsWithCommas() {
  const input = "name,notes\nAlice,\"likes, apples\"\nBob,\"hello, world\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0].notes, "likes, apples", "Quoted field should include commas");
  assertEqual(result.rows[1].notes, "hello, world", "Second quoted field should include commas");
})();

(function testEscapedQuotes() {
  const input = "name,quote\nAlice,\"She said \"\"Hi\"\"\"";
  const result = parseCSV(input);
  assertEqual(result.rows[0].quote, "She said \"Hi\"", "Escaped quotes should be parsed");
})();

(function testCustomDelimiters() {
  const input = "name;age|Alice;32|Bob;40";
  const result = parseCSV(input, { delimiter: ";", lineSeparator: "|" });
  assert(result.rows.length === 2, "Should parse rows with custom delimiter");
  assertEqual(result.rows[0], { name: "Alice", age: 32 }, "Custom delimiter row 1");
})();

(function testTypeCoercion() {
  const input = "val\n42\n3.14\nTRUE\nfalse\nnull\n\nhello";
  const result = parseCSV(input);
  assertEqual(result.rows[0].val, 42, "Integer should coerce to number");
  assertEqual(result.rows[1].val, 3.14, "Float should coerce to number");
  assertEqual(result.rows[2].val, true, "TRUE should coerce to boolean");
  assertEqual(result.rows[3].val, false, "false should coerce to boolean");
  assertEqual(result.rows[4].val, null, "null should coerce to null");
  assertEqual(result.rows[5].val, null, "Empty string should coerce to null");
  assertEqual(result.rows[6].val, "hello", "Other strings should remain strings");
})();

(function testMalformedRows() {
  const input = "a,b\n1\n2,3,4";
  const result = parseCSV(input);
  assert(result.errors.length === 2, "Should collect errors for malformed rows");
  assertEqual(result.errors[0], { row: 2, message: "Expected 2 fields but got 1" }, "First error should include row number");
  assertEqual(result.errors[1], { row: 3, message: "Expected 2 fields but got 3" }, "Second error should include row number");
})();

(function testFilterFunctionality() {
  const input = "name,age\nAlice,30\nBob,20\nCara,40";
  const result = parseCSV(input);
  const filtered = result.filter((row) => row.age > 25);
  assert(filtered.length === 2, "Filter should return matching rows");
  assertEqual(filtered.map((row) => row.name), ["Alice", "Cara"], "Filter should include correct rows");
})();

(function testAggregationMethods() {
  const input = "name,amount,group\nA,10,one\nB,20,one\nC,30,two";
  const result = parseCSV(input);
  assert(result.sum("amount") === 60, "Sum should total numeric values");
  assert(result.average("amount") === 20, "Average should compute mean");
  assert(result.count() === 3, "Count should return total rows");
  const grouped = result.groupBy("group");
  assert(grouped.get("one")?.length === 2, "Group should include two rows for 'one'");
  assert(grouped.get("two")?.length === 1, "Group should include one row for 'two'");
})();

(function testEdgeCases() {
  const empty = parseCSV("");
  assert(empty.rows.length === 0, "Empty input should have no rows");
  assert(empty.headers.length === 0, "Empty input should have no headers");

  const singleColumn = parseCSV("value\n1\n2");
  assertEqual(singleColumn.headers, ["value"], "Single column header should parse");
  assertEqual(singleColumn.rows[1], { value: 2 }, "Single column row should parse");

  const singleRow = parseCSV("a,b\n1,2");
  assert(singleRow.rows.length === 1, "Single row input should parse one row");

  const largeField = "x".repeat(10000);
  const largeInput = `data\n${largeField}`;
  const largeResult = parseCSV(largeInput);
  assert(largeResult.rows[0].data.length === 10000, "Large field should be preserved");
})();

console.log("All tests passed");

